// src/views/liste.owner.js
import React, { useState } from "react";
import FooterRecharche from "../components/Footers/footer.recharche";
import Navbar from "../components/Navbars/AuthNavbar";
import OwnerCard from "../components/Common/OwnerCard.js";
import { useHistory } from "react-router-dom";

export default function ListeOwner() {
  const history = useHistory();
  const [searchTerm, setSearchTerm] = useState("");
  
  // Pour simuler le rôle de l'utilisateur (true = manager, false = visiteur)
  const [isManager, setIsManager] = useState(true); // À changer selon le rôle réel
  
  const [owners, setOwners] = useState([
    {
      id: 1,
      name: "Ahmed Benali",
      location: "Alger, Algérie",
      bio: "Passionné par la cuisine traditionnelle algérienne, je souhaite ouvrir mon propre restaurant pour faire découvrir les saveurs authentiques de notre terroir.",
      image: "https://randomuser.me/api/portraits/men/32.jpg",
      restaurantId: null
    },
    {
      id: 2,
      name: "Jean Dupont",
      location: "Paris, France",
      bio: "Amoureux du café et de la pâtisserie française, je cherche à reprendre un établissement pour partager ma passion.",
      image: "https://randomuser.me/api/portraits/men/45.jpg",
      restaurantId: null
    },
    {
      id: 3,
      name: "Marco Rossi",
      location: "Rome, Italie",
      bio: "Chef italien avec 25 ans d'expérience, je souhaite devenir propriétaire de mon propre restaurant.",
      image: "https://randomuser.me/api/portraits/men/68.jpg",
      restaurantId: null
    },
    {
      id: 4,
      name: "Kenji Tanaka",
      location: "Tokyo, Japon",
      bio: "Maître sushi formé au Japon, je cherche un établissement pour partager l'art du sushi authentique.",
      image: "https://randomuser.me/api/portraits/men/89.jpg",
      restaurantId: null
    },
    {
      id: 5,
      name: "Sophia Martinez",
      location: "Lyon, France",
      bio: "Pâtissière passionnée, je rêve d'ouvrir ma propre boutique de pâtisseries artisanales.",
      image: "https://randomuser.me/api/portraits/women/45.jpg",
      restaurantId: null
    }
  ]);

  const [claimedOwners, setClaimedOwners] = useState([]);
  const [selectedOwner, setSelectedOwner] = useState(null);
  const [showModal, setShowModal] = useState(false);

  const filteredOwners = owners.filter(owner =>
    owner.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    owner.location.toLowerCase().includes(searchTerm.toLowerCase()) ||
    owner.bio.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleClaimRestaurant = (owner) => {
    // Mettre à jour le propriétaire avec le restaurantId
    const updatedOwners = owners.map(o => 
      o.id === owner.id ? { ...o, restaurantId: Date.now() } : o
    );
    setOwners(updatedOwners);
    setClaimedOwners([...claimedOwners, owner.id]);
    
    // Optionnel: sauvegarder dans localStorage
    localStorage.setItem(`restaurant_owner_${owner.id}`, "claimed");
  };

  const handleSearch = (value) => {
    setSearchTerm(value);
  };

  const style = `
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }
    
    @keyframes fadeIn {
      from { opacity: 0; transform: translateY(20px); }
      to { opacity: 1; transform: translateY(0); }
    }
    
    .owners-container {
      background: linear-gradient(135deg, #0a0a2a, #1a1a3a, #0d0d2b);
      min-height: 100vh;
      padding-top: 80px;
      padding-bottom: 80px;
    }
    
    .owners-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
      gap: 25px;
      max-width: 1400px;
      margin: 0 auto;
      padding: 20px;
    }
    
    .manager-badge {
      position: fixed;
      bottom: 20px;
      right: 20px;
      background: #22c55e;
      color: white;
      padding: 8px 16px;
      border-radius: 30px;
      font-size: 0.8rem;
      font-weight: bold;
      z-index: 100;
      box-shadow: 0 5px 15px rgba(34,197,94,0.3);
    }
    
    .empty-state {
      text-align: center;
      padding: 50px;
      color: rgba(255,255,255,0.5);
    }
    
    .empty-state-icon {
      font-size: 4rem;
      margin-bottom: 15px;
      opacity: 0.5;
    }
    
    @media (max-width: 768px) {
      .owners-grid {
        grid-template-columns: 1fr;
        padding: 15px;
      }
    }
  `;

  return (
    <>
      <style>{style}</style>
      <Navbar />
      
      <div className="owners-container">
        <div className="owners-grid">
          {filteredOwners.length === 0 ? (
            <div className="empty-state">
              <div className="empty-state-icon">👤</div>
              <p>Aucun propriétaire trouvé</p>
              <p style={{ fontSize: '0.8rem' }}>Essayez une autre recherche</p>
            </div>
          ) : (
            filteredOwners.map(owner => (
              <OwnerCard 
                key={owner.id}
                owner={owner}
                isManager={isManager}
                onClaimRestaurant={handleClaimRestaurant}
              />
            ))
          )}
        </div>
      </div>
      
      <FooterRecharche 
        type="owners"
        onSearch={handleSearch}
        placeholder="🔍 Rechercher un propriétaire par nom, ville ou description..."
      />
      
      {isManager && (
        <div className="manager-badge">
          👑 Mode Manager - Vous pouvez attribuer les restaurants
        </div>
      )}
    </>
  );
}
